import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';
import { SocketProvider } from './context/SocketContext';

// Pages
import LandingPage from './pages/LandingPage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import SearchPage from './pages/SearchPage';
import ProviderDetailPage from './pages/ProviderDetailPage';
import BookingPage from './pages/BookingPage';
import UserDashboard from './pages/UserDashboard';
import ProviderDashboard from './pages/ProviderDashboard';
import ProviderOnboarding from './pages/ProviderOnboarding';
import ChatPage from './pages/ChatPage';
import AdminDashboard from './pages/AdminDashboard';
import BookingDetailPage from './pages/BookingDetailPage';

const ProtectedRoute = ({ children, roles }) => {
  const { user, loading } = useAuth();
  if (loading) return <div className="app-loading"><div className="spinner" /></div>;
  if (!user) return <Navigate to="/login" replace />;
  if (roles && !roles.includes(user.role)) return <Navigate to="/" replace />;
  return children;
};

const AppRoutes = () => {
  const { user } = useAuth();
  return (
    <Routes>
      <Route path="/" element={<LandingPage />} />
      <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <LoginPage />} />
      <Route path="/register" element={user ? <Navigate to="/dashboard" /> : <RegisterPage />} />
      <Route path="/search" element={<SearchPage />} />
      <Route path="/provider/:id" element={<ProviderDetailPage />} />

      <Route path="/dashboard" element={
        <ProtectedRoute>
          {user?.role === 'admin' ? <Navigate to="/admin" /> :
           user?.role === 'provider' ? <ProviderDashboard /> : <UserDashboard />}
        </ProtectedRoute>
      } />

      <Route path="/book/:providerId" element={
        <ProtectedRoute roles={['user']}><BookingPage /></ProtectedRoute>
      } />

      <Route path="/bookings/:id" element={
        <ProtectedRoute><BookingDetailPage /></ProtectedRoute>
      } />

      <Route path="/provider-onboarding" element={
        <ProtectedRoute><ProviderOnboarding /></ProtectedRoute>
      } />

      <Route path="/chat" element={
        <ProtectedRoute><ChatPage /></ProtectedRoute>
      } />
      <Route path="/chat/:userId" element={
        <ProtectedRoute><ChatPage /></ProtectedRoute>
      } />

      <Route path="/admin/*" element={
        <ProtectedRoute roles={['admin']}><AdminDashboard /></ProtectedRoute>
      } />

      <Route path="*" element={<Navigate to="/" />} />
    </Routes>
  );
};

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <SocketProvider>
          <AppRoutes />
          <Toaster
            position="top-right"
            toastOptions={{
              duration: 3000,
              style: { background: '#1a1a2e', color: '#e2e8f0', border: '1px solid #334155' },
            }}
          />
        </SocketProvider>
      </AuthProvider>
    </BrowserRouter>
  );
}
